/**
 * @file utils/ai-performance-monitor.js
 * @description This module initializes a performance monitor specifically for Largest Contentful Paint (LCP).
 * It uses the Performance Observer API to track LCP and logs the result to the console,
 * providing a simple AI-like assessment and recommendations based on common LCP thresholds.
 *
 * LCP is a Core Web Vital that measures the render time of the largest image or text block visible within the viewport,
 * relative to when the page first started loading. A fast LCP helps assure the user that the page is useful.
 */

/**
 * Initializes the LCP performance monitor.
 * This function sets up a PerformanceObserver to track 'largest-contentful-paint' entries.
 * It reports the LCP value and provides an AI-like assessment with recommendations.
 */
export function initLCPMonitor() {
  if (typeof window === 'undefined' || !window.PerformanceObserver) {
    console.warn('PerformanceObserver API not available. LCP monitoring skipped.');
    return;
  }

  let lcpReported = false;

  const observer = new PerformanceObserver((entryList) => {
    const entries = entryList.getEntries();
    const lastEntry = entries[entries.length - 1];

    if (lastEntry && !lcpReported) {
      const lcpValue = lastEntry.renderTime || lastEntry.loadTime; // Use renderTime if available, fallback to loadTime
      const lcpSeconds = lcpValue / 1000; // Convert milliseconds to seconds

      console.groupCollapsed('%cAI Performance Monitor: LCP Report', 'color: #4CAF50; font-weight: bold;');
      console.log(`%cLargest Contentful Paint (LCP): %c${lcpSeconds.toFixed(2)}s`, 'font-weight: bold;', 'color: #2196F3; font-weight: bold;');

      let assessment = '';
      let recommendation = '';
      let color = '';

      if (lcpSeconds <= 2.5) {
        assessment = 'Excellent!';
        recommendation = 'Your LCP is well within the "Good" threshold. Keep up the great work!';
        color = '#4CAF50'; // Green
      } else if (lcpSeconds > 2.5 && lcpSeconds <= 4.0) {
        assessment = 'Needs Improvement.';
        recommendation = 'Your LCP is in the "Needs Improvement" range. Consider optimizing image sizes, deferring non-critical CSS/JS, and ensuring server response times are fast.';
        color = '#FFC107'; // Amber
      } else {
        assessment = 'Poor Performance!';
        recommendation = 'Your LCP is in the "Poor" range. This significantly impacts user experience. Focus on critical rendering path optimizations: prioritize above-the-fold content, optimize server response time, use a CDN, and ensure efficient image loading (lazy loading, proper formats).';
        color = '#F44336'; // Red
      }

      console.log(`%cAssessment: %c${assessment}`, 'font-weight: bold;', `color: ${color}; font-weight: bold;`);
      console.log(`%cRecommendation: %c${recommendation}`, 'font-weight: bold;', 'color: #607D8B;');
      console.groupEnd();

      lcpReported = true;
      observer.disconnect(); // Disconnect once LCP is reported
    }
  });

  try {
    observer.observe({ type: 'largest-contentful-paint', buffered: true });
  } catch (error) {
    console.error('Failed to observe largest-contentful-paint:', error);
  }

  // Fallback for browsers that might not support 'largest-contentful-paint' or for debugging
  // This ensures the observer is disconnected even if LCP isn't reported for some reason
  setTimeout(() => {
    if (!lcpReported) {
      console.warn('LCP not reported within 10 seconds. Observer disconnected without reporting.');
      observer.disconnect();
    }
  }, 10000); // Disconnect after 10 seconds if no LCP is reported
}

// Automatically initialize the monitor when the script loads,
// assuming this module is imported and executed in a browser context.
// If you prefer to manually call it, remove this line.
if (typeof window !== 'undefined') {
  initLCPMonitor();
}

